cd /workspace/floci && cat > /tmp/RawDeliveryRepro.java <<'EOF'
import io.github.hectorvent.floci.core.common.RegionResolver;
import io.github.hectorvent.floci.core.storage.InMemoryStorage;
import io.github.hectorvent.floci.services.sns.SnsService;
import io.github.hectorvent.floci.services.sns.model.Subscription;
import io.github.hectorvent.floci.services.sns.model.Topic;
import io.github.hectorvent.floci.services.sqs.SqsService;
import io.github.hectorvent.floci.services.sqs.model.Message;
import io.github.hectorvent.floci.services.sqs.model.Queue;

import java.lang.reflect.Constructor;
import java.util.List;
import java.util.Map;

public class RawDeliveryRepro {
    static final String REGION = "us-east-1";
    static final String ACCOUNT = "000000000000";
    static final String BASE_URL = "http://localhost:4566";
    static final String RAW_BODY = "{\"orderId\":\"123\"}";

    public static void main(String[] args) throws Exception {
        assertPublishBody("raw-lower", "true", RAW_BODY);
        assertPublishBody("raw-upper", "TRUE", RAW_BODY);
        assertPublishBody("wrapped-false", "false", null);
        assertPublishBody("wrapped-default", null, null);
        assertBatchRawBody();
        System.out.println("RawDeliveryRepro passed");
    }

    static void assertPublishBody(String queueName, String rawAttributeValue, String expectedRawBody) throws Exception {
        SqsService sqsService = newSqsService();
        SnsService snsService = newSnsService(sqsService);

        Queue queue = sqsService.createQueue(queueName, null, REGION);
        Topic topic = snsService.createTopic("topic-" + queueName, null, null, REGION);
        Subscription sub = subscribeQueue(snsService, topic, queueName);
        if (rawAttributeValue != null) {
            snsService.setSubscriptionAttribute(sub.getSubscriptionArn(), "RawMessageDelivery", rawAttributeValue, REGION);
        }

        snsService.publish(topic.getTopicArn(), null, RAW_BODY, null, REGION);
        String body = receiveOne(sqsService, queue);
        if (expectedRawBody != null) {
            assertEquals(expectedRawBody, body, queueName + " should receive raw body");
        } else {
            assertWrapped(body, queueName + " should receive SNS envelope");
        }
    }

    static void assertBatchRawBody() throws Exception {
        SqsService sqsService = newSqsService();
        SnsService snsService = newSnsService(sqsService);

        Queue queue = sqsService.createQueue("raw-batch", null, REGION);
        Topic topic = snsService.createTopic("topic-raw-batch", null, null, REGION);
        Subscription sub = subscribeQueue(snsService, topic, "raw-batch");
        snsService.setSubscriptionAttribute(sub.getSubscriptionArn(), "RawMessageDelivery", "true", REGION);

        snsService.publishBatch(topic.getTopicArn(), List.of(Map.of("Id", "one", "Message", RAW_BODY)), REGION);
        assertEquals(RAW_BODY, receiveOne(sqsService, queue), "batch publish should receive raw body");
    }

    static Subscription subscribeQueue(SnsService snsService, Topic topic, String queueName) {
        String endpointArn = "arn:aws:sqs:" + REGION + ":" + ACCOUNT + ":" + queueName;
        return snsService.subscribe(topic.getTopicArn(), "sqs", endpointArn, REGION);
    }

    static String receiveOne(SqsService sqsService, Queue queue) {
        List<Message> messages = sqsService.receiveMessage(queue.getQueueUrl(), 1, 30, 0, REGION);
        if (messages.size() != 1) {
            throw new AssertionError("Expected one SQS message, got " + messages.size());
        }
        String body = messages.getFirst().getBody();
        System.out.println(queue.getQueueName() + " received body: " + body);
        return body;
    }

    static void assertWrapped(String body, String message) {
        if (!body.contains("\"Type\":\"Notification\"") || !body.contains("\"Message\":\"{\\\"orderId\\\":\\\"123\\\"}\"")) {
            throw new AssertionError(message + "; got " + body);
        }
    }

    static void assertEquals(String expected, String actual, String message) {
        if (!expected.equals(actual)) {
            throw new AssertionError(message + "; expected " + expected + " but got " + actual);
        }
    }

    static SqsService newSqsService() throws Exception {
        Constructor<SqsService> ctor = SqsService.class.getDeclaredConstructor(
                io.github.hectorvent.floci.core.storage.StorageBackend.class,
                int.class, int.class, String.class);
        ctor.setAccessible(true);
        return ctor.newInstance(new InMemoryStorage<>(), 30, 262144, BASE_URL);
    }

    static SnsService newSnsService(SqsService sqsService) throws Exception {
        Constructor<SnsService> ctor = SnsService.class.getDeclaredConstructor(
                io.github.hectorvent.floci.core.storage.StorageBackend.class,
                io.github.hectorvent.floci.core.storage.StorageBackend.class,
                RegionResolver.class,
                SqsService.class,
                io.github.hectorvent.floci.services.lambda.LambdaService.class);
        ctor.setAccessible(true);
        return ctor.newInstance(new InMemoryStorage<>(), new InMemoryStorage<>(),
                new RegionResolver(REGION, ACCOUNT), sqsService, null);
    }
}
EOF
